import React, { useEffect } from 'react';

function Component(props) {
  const num = props.number;

  useEffect(() => {
    console.log(`Table of ${num}:`);
    for (let i = 1; i <= 10; i++) {
      console.log(`${num} x ${i} = ${num * i}`);
    }
  }, [num]);

  return (
    <div>
      <h2>Table of {num} printed in console.</h2>
    </div>
  );
}
export default Component;

